// Compute S1/S2/S4, prefilters, evidence (spec docs/scorer-spec.md par.2, par.5).
// route field drives the Route switch downstream.
const prospect = $('Split Queue').item.json;
const resp = $json.body ?? $json;

if (resp.error) {
  const route = resp.error.code === 110 ? 'unscoreable_personal' : 'fetch_error';
  return { json: { ...prospect, route, error_message: resp.error.message } };
}
const bd = resp.business_discovery;
if (!bd) return { json: { ...prospect, route: 'fetch_error', error_message: 'no business_discovery in response' } };

const followers = bd.followers_count || 0;
const mediaCount = bd.media_count || 0;
if (followers < 500 || followers > 20000 || mediaCount === 0) {
  return { json: { ...prospect, route: 'disqualified', followers } };
}
const media = (bd.media && bd.media.data) || [];

// S1 - posting frequency
const now = Date.now();
const posts90 = media.filter(m => now - new Date(m.timestamp).getTime() <= 90 * 864e5).length;
const weekly = posts90 / 12.857;
let s1;
if (media.length === 12 && posts90 === 12) s1 = 0;   // window saturated: rate >= 1/wk
else if (weekly < 0.25) s1 = 20;
else if (weekly < 0.5) s1 = 15;
else if (weekly < 1) s1 = 10;
else s1 = 0;

// S2 - engagement vs segment benchmark (initial table; recalibrate after 200 scored)
const BENCH = { estetica:{er:.035,c:.002}, odonto:{er:.025,c:.0012}, salao:{er:.03,c:.0015},
  restaurante:{er:.02,c:.001}, pet:{er:.04,c:.0025}, fitness:{er:.03,c:.0015}, outro:{er:.03,c:.0015} };
const bench = BENCH[prospect.segment] || BENCH.outro;
let s2, er = null, benchUsed = bench.er;
if (media.length < 4) {
  s2 = 12;                                            // thin data ~ weak (spec par.8)
} else {
  const hidden = media.filter(m => !m.like_count && (m.comments_count || 0) > 0).length;
  let vals;
  if (hidden >= 6) { vals = media.map(m => (m.comments_count || 0) / followers); benchUsed = bench.c; }
  else vals = media.map(m => ((m.like_count || 0) + (m.comments_count || 0)) / followers);
  const top = vals.indexOf(Math.max(...vals));        // drop single viral outlier
  vals = vals.filter((_, i) => i !== top);
  er = vals.reduce((a, b) => a + b, 0) / vals.length;
  const pct = er / benchUsed;
  s2 = pct < 0.4 ? 20 : pct < 0.7 ? 12 : pct < 1 ? 6 : 0;
}

// S4 - link in bio
const bio = bd.biography || '';
const s4 = (bd.website || /(wa\.me|api\.whatsapp|linktr\.ee|bit\.ly|beacons|linkin\.bio|https?:\/\/)/i.test(bio)) ? 0 : 10;

const fmtPct = x => (x * 100).toFixed(1).replace('.', ',') + '%';
const evidence = [];
if (s1 > 0) evidence.push({ signal: 'S1', pts: s1, text: `só ${posts90} publicações nos últimos 3 meses` });
if (er !== null && s2 > 0) evidence.push({ signal: 'S2', pts: s2, text: `engajamento de ${fmtPct(er)} — a média do setor é ${fmtPct(benchUsed)}` });
if (s4 > 0) evidence.push({ signal: 'S4', pts: s4, text: 'sem link de agendamento ou WhatsApp na bio' });

// fetch image URLs same run - CDN links expire (spec par.8)
const images = media.slice(0, 9)
  .map(m => m.media_type === 'VIDEO' ? (m.thumbnail_url || m.media_url) : (m.media_url || m.thumbnail_url))
  .filter(Boolean);

return { json: { ...prospect, route: 'score', followers, posts_90d: posts90, er, s1, s2, s4, biography: bio, images, evidence } };

// Parse P1/P2, compute S3/S5, assemble prospect_scores upsert row (spec par.3, par.5, par.6).
const d = $('Compute Signals').item.json;

function parseClaude(resp) {
  const text = (resp.content || []).map(c => c.text || '').join('');
  return JSON.parse(text.replace(/```json|```/gi, '').trim());
}

let p1, p2;
try {
  p1 = parseClaude($('Claude P1').item.json);
  p2 = parseClaude($json);
} catch (e) {
  return { json: { prospect_id: d.id, ig_handle: d.ig_handle, segment: d.segment,
    followers: d.followers, s1: d.s1, s2: d.s2, s4: d.s4, er: d.er, posts_90d: d.posts_90d,
    evidence: d.evidence, status: 'llm_error',
    llm_raw: { p1: $('Claude P1').item.json, p2: $json, parse_error: e.message } } };
}

const s3 = (!p1.has_offer && !p1.has_cta) ? 15 : (!p1.has_offer || !p1.has_cta) ? 8 : 0;
const s5 = p2.consistency_1_5 <= 2 ? 15 : p2.consistency_1_5 === 3 ? 8 : 0;

const evidence = [...d.evidence];
if (s3 === 15) evidence.push({ signal: 'S3', pts: 15, text: 'a bio não diz o que vocês oferecem nem como agendar' });
else if (s3 === 8) evidence.push({ signal: 'S3', pts: 8, text: p1.notes_ptbr || 'bio sem oferta clara ou sem chamada para ação' });
if (s5 > 0 && p2.grid_summary_ptbr) evidence.push({ signal: 'S5', pts: s5, text: p2.grid_summary_ptbr });
evidence.sort((a, b) => b.pts - a.pts);

const auto = d.s1 + d.s2 + s3 + d.s4 + s5;   // auto_score is a generated column; not inserted
return { json: {
  prospect_id: d.id, ig_handle: d.ig_handle, followers: d.followers, segment: d.segment,
  s1: d.s1, s2: d.s2, s3, s4: d.s4, s5,
  er: d.er, posts_90d: d.posts_90d,
  dominant_colors: p2.dominant_colors_hex || [],   // persisted ALWAYS - seeds Frame brand kit
  evidence, llm_raw: { p1, p2 },
  status: auto >= 50 ? 'in_review' : 'auto_scored'
} };

// unscoreable_personal / disqualified: record status so the row leaves the queue
const d = $json;
return { json: { prospect_id: d.id, ig_handle: d.ig_handle, segment: d.segment,
  followers: d.followers ?? null, status: d.route } };
